"""
Dieses Skript erstellt die mitarbeiter.db im gleichen Verzeichnis.
Einfach einmal ausführen: python erstelle_datenbank.py
"""
import sqlite3
import os

BASE_DIR = os.path.dirname(os.path.abspath(__file__))
db_path = os.path.join(BASE_DIR, "mitarbeiter.db")

conn = sqlite3.connect(db_path)
cursor = conn.cursor()

cursor.executescript("""
CREATE TABLE IF NOT EXISTS anrede (
    ID_Anrede INTEGER NOT NULL PRIMARY KEY,
    Anrede    TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS ort (
    ID_Ort INTEGER NOT NULL PRIMARY KEY,
    PLZ    TEXT NOT NULL,
    Ort    TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS mitarbeiter (
    ID_Mitarbeiter INTEGER NOT NULL PRIMARY KEY,
    Anrede         INTEGER NOT NULL,
    Vorname        TEXT NOT NULL,
    Name           TEXT NOT NULL,
    Strasse        TEXT NOT NULL,
    Hausnr         TEXT NOT NULL,
    ID_Ort         INTEGER NOT NULL,
    Telefon        TEXT NOT NULL,
    FOREIGN KEY (Anrede) REFERENCES anrede(ID_Anrede),
    FOREIGN KEY (ID_Ort) REFERENCES ort(ID_Ort)
);
""")

# --- anrede ---
cursor.executemany("INSERT OR IGNORE INTO anrede VALUES (?, ?)", [
    (1, 'Herr'), (2, 'Frau'), (3, 'Divers')
])

